    print("=" * 60)

    if os.path.exists(archive_path):
        raise RuntimeError("Archive file already exists: {0}".format(archive_path))

    handler = FORMAT_HANDLERS[validated_format]
    result_path = handler(validated_path, archive_path)

    if os.path.exists(result_path):
        file_size = os.path.getsize(result_path)
        print("")
