def _format_size(size_bytes):
    """Format file size in human-readable form."""
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size_bytes < 1024.0:
            return "{0:.2f} {1}".format(size_bytes, unit)
        size_bytes /= 1024.0
    return "{0:.2f} PB".format(size_bytes)


