def parse_arguments():
    """Parse command-line arguments manually for maximum compatibility."""
    import getopt

    usage = """Usage: {0} [OPTIONS] <directory> <format>

Create compressed backup archives of directories.

Arguments:
  directory          Path to the directory to back up
  format             Compression format: tar.gz, tar.bz2, zip, 7z

Options:
  -o, --output DIR   Output directory for the archive (default: current directory)
  -l, --list         List available compression formats and exit
  -h, --help         Show this help message and exit

Examples:
  {0} /home/user tar.gz
  {0} -o /backups /home/user zip
  {0} --output /backups /var/www 7z
""".format(sys.argv[0])

    try:
        opts, args = getopt.getopt(
            sys.argv[1:],
            'ho:l',
            ['help', 'output=', 'list']
        )
    except getopt.GetoptError as e:
        print("Error: {0}".format(e), file=sys.stderr)
        print(usage, file=sys.stderr)
        sys.exit(1)

    output_dir = None

    for opt, val in opts:
        if opt in ('-h', '--help'):
            print(usage)
            sys.exit(0)
        elif opt in ('-l', '--list'):
            list_formats()
            sys.exit(0)
        elif opt in ('-o', '--output'):
            output_dir = val

    if len(args) < 2:
        print("Error: Both directory and format arguments are required.", file=sys.stderr)
        print(usage, file=sys.stderr)
        sys.exit(1)

    if len(args) > 2:
        print("Error: Too many arguments.", file=sys.stderr)
        print(usage, file=sys.stderr)
        sys.exit(1)

    return {
        'directory': args[0],
        'format': args[1],
        'output_dir': output_dir,
    }


